#include <bits/stdc++.h>
using namespace std;
int a1[5005],ans[5005];
int main()
{
    string a;
    long long b;
    cin>>a>>b;
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    long long yushu=0,temp=0;
    for(int i=0;i<=a.size()-1;i++)
    {
        temp=yushu*10+a1[i];
        ans[i]=temp/b;
        yushu=temp%b;
    }

    int start=0;
    while(ans[start]==0&&start<a.size()-1)
    {
        start++;
    }
    for(int i=start;i<=a.size()-1;i++)
    {
        cout<<ans[i];
    }
    return 0;
}
